+type Clause = { patterns: Pattern<any>[]; predicate?: (value: any) => unknown; handler: (selection: unknown, value: any) => unknown };
+type Entry = Clause | { tap: (result: unknown) => void };
+
+/**
+ * Creates a pattern matching expression which runs every matching handler.
+ * Omitting the value creates a reusable matcher; use `.toFunction()` to compile it.
+ */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(value?: unknown): MatchEach<any, any> {
+  return new MatchEachExpression([], arguments.length === 0 ? true : false, value) as any;
+}
+
+class MatchEachExpression {
+  constructor(private entries: Entry[], private isCompiled: boolean, private value?: unknown) {}
+
+  with(...args: any[]): MatchEachExpression {
+    const handler = args[args.length - 1];
+    const patterns: Pattern<any>[] = [args[0]];
+    let predicate: ((value: unknown) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+    return new MatchEachExpression([...this.entries, { patterns, predicate, handler }], this.isCompiled, this.value);
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown): MatchEachExpression {
+    return new MatchEachExpression([...this.entries, { patterns: [], predicate, handler: (_selection, value) => handler(value) }], this.isCompiled, this.value);
+  }
+
+  tap(callback: (result: unknown) => void): MatchEachExpression {
+    return new MatchEachExpression([...this.entries, { tap: callback }], this.isCompiled, this.value);
+  }
+
+  otherwise(handler: (value: unknown) => unknown): unknown[] {
+    const results = this.evaluate(this.value);
+    return results.length ? results : [handler(this.value)];
+  }
+
+  exhaustive(fallback = defaultCatcher): unknown[] {
+    const results = this.evaluate(this.value);
+    return results.length ? results : [fallback(this.value)];
+  }
+
+  run(): unknown[] { return this.exhaustive(); }
+  returnType() { return this; }
+  narrow() { return this; }
